	.TITLE	TICONE	.PROC	M680002	.REF	DRIVERS	.REF	LIB	.REF	SM8	.REF	FOS	.REF	ICONEGCICF	=	'I		; fonte des icnesGCICS	=	'A		; style/chasse des icnesGCICT	=	24		; taille des icnesGCTXF	=	'N		; fonte du texteGCTXS	=	'E!2^7		; style/chasse du texteGCTXT	=	11		; taille du texte	.LOC	0OPDDIS:	.BLKB	4OBDIS:	.BLKB	100LGVAR:	.LOC	0START:	.W	LIB,?OPELIB	LOAD.L	A6,#R16"VAR	LOAD.L	A4,A6	LOAD.W	D4,#LGVAR10$:	CLR.B	(A4+)	DEC.W	D4	JUMP,NE 10$	LOAD.W	D3,#2	.W	LIB,?MOUSE	.W	LIB,?GCHDIS	; D6 <-- canal cran	LOAD.W	D3,#TYPWDO	; D3 <-- type fentre cran	LOAD.L	D4,#4		; D4 <-- longueur demande	LOAD.L	A4,#(A6)+OPDDIS	; A4 <-- ^buffer	.W	FOS,?RSTATUS	; demande le ^rel !	JUMP,NE ERFAT	LOAD.L	A3,#R16"NAME	LOAD.W	D3,#ICONE_FIRST	.W	LIB_OPEN	LOAD.L	A3,#(A6)+OBDIS	LOAD.B	(A3+),#LOADGC	LOAD.B	(A3+),#GCICF	LOAD.B	(A3+),#GCICS	LOAD.B	(A3+),#GCICT	LOAD.B	(A3+),#USEGC	LOAD.B	(A3+),#GCICF	LOAD.B	(A3+),#GCICS	LOAD.B	(A3+),#GCICT	LOAD.L	D3,A3	LOAD.L	A3,#(A6)+OBDIS	SUB.L	D3,A3	.W	LIB,?STRING	LOAD.L	A0,(A6)+OPDDIS	.W	ICONE_CADRE	LOAD.L	A3,#R16"LIC1	.W	ICONE_AFF	.W	LIB,?GETCAR	.W	ICONE_DET	LOAD.L	A3,#R16"LIC2	.W	ICONE_AFF	.W	LIB,?GETCAR	.W	ICONE_DET	LOAD.L	A3,#R16"LIC3	.W	ICONE_AFF	.W	LIB,?GETCAR	.W	ICONE_DET	.W	LIB_CLOSEERFAT:	.W	LIB,?CLOLIB	.W	FOS,?STOP	EXITLIC1:	.B	0	.B	3,3,3	.B	2,2,2	.B	0,0,0	.B	12,12,12	.B	0,0,0LIC2:	.B	0	.B	15,15,15	.B	16,16,16	.B	17,17,17	.B	18,4,19	.B	0,0,0LIC3:	.B	19	.B	10,10,10	.B	11,11,11	.B	3,3,3	.B	5,5,5	.B	13,13,13	.EVENNAME:	.ASCIZ	"ICONE"	.EVENVAR:	.FILLB	LGVAR,0	.END	START